let panier = JSON.parse(localStorage.getItem('bouddhas_panier') || '[]');
function majCompteur() {
 const el = document.getElementById('cart-count');
 if (el) el.textContent = panier.length;
}
majCompteur();
function showToast(msg) {
 const t = document.getElementById('toast');
 if (!t) return;
 t.textContent = msg;
 t.style.display = 'block';
 setTimeout(() => t.style.display = 'none', 2500);
}
async function addToCart(handle, qty = 1, variantId = null) {
 if (!window.__productsCache) {
 window.__productsCache = await shopify.getProducts(100);
 }
 const p = window.__productsCache.find(x => x.handle === handle);
 if (!p) return;
 if (!variantId) {
 variantId = p.variants?.edges?.[0]?.node?.id || null;
 }
 for (let i = 0; i < qty; i++) {
 panier.push({
 handle,
 variantId,
 title: p.title,
 price: p.priceRange.minVariantPrice.amount,
 img: p.images?.edges?.[0]?.node?.url || ''
 });
 }
 localStorage.setItem('bouddhas_panier', JSON.stringify(panier));
 majCompteur();
 showToast(`✅ "${p.title}" ajouté (${qty})`);
}
function retirerDuPanier(handle) {
 panier = panier.filter(p => p.handle !== handle);
 localStorage.setItem('bouddhas_panier', JSON.stringify(panier));
 majCompteur();
 location.reload();
}
function updateQty(handle, delta) {
 if (delta > 0) {
 const item = panier.find(p => p.handle === handle);
 if (item) {
 panier.push({ ...item });
 }
 } else if (delta < 0) {
 const idx = panier.findIndex(p => p.handle === handle);
 if (idx !== -1) panier.splice(idx, 1);
 }
 localStorage.setItem('bouddhas_panier', JSON.stringify(panier));
 majCompteur();
 location.reload();
}
async function createShopifyCheckout() {
 if (panier.length === 0) return;
 showToast('🔄 Préparation du checkout...');
 try {
 const grouped = {};
 for (const p of panier) {
 if (!p.variantId) continue;
 if (!grouped[p.variantId]) grouped[p.variantId] = { merchandiseId: p.variantId, quantity: 0 };
 grouped[p.variantId].quantity += 1;
 }
 const items = Object.values(grouped);
 if (items.length === 0) {
 showToast('❌ Aucun variant disponible pour le checkout');
 return;
 }
 const mutation = `
 mutation {
 cartCreate(input: { lines: [${items.map(i => `{ merchandiseId: "${i.merchandiseId}", quantity: ${i.quantity} }`).join(',')}] }) {
 cart { id checkoutUrl }
 userErrors { field message }
 }
 }
 `;
 const res = await fetch(CONFIG.apiUrl, {
 method: 'POST',
 headers: {
 'Content-Type': 'application/json',
 'X-Shopify-Storefront-Access-Token': CONFIG.storefrontToken
 },
 body: JSON.stringify({ query: mutation })
 });
 const data = await res.json();
 if (data.data?.cartCreate?.cart?.checkoutUrl) {
 window.location.href = data.data.cartCreate.cart.checkoutUrl;
 } else {
 const err = data.data?.cartCreate?.userErrors?.[0]?.message || 'Erreur inconnue';
 showToast(`❌ ${err}`);
 }
 } catch (e) {
 showToast(`❌ Erreur: ${e.message}`);
 }
}
document.addEventListener('DOMContentLoaded', () => {
 const items = document.getElementById('cart-items');
 const summary = document.getElementById('cart-summary');
 if (!items) return;
 if (panier.length === 0) {
 items.innerHTML = `
 <div style="text-align:center;padding:4rem;">
 <div style="font-size:4rem;margin-bottom:1.5rem;">🛒</div>
 <h2 style="color:var(--dark);margin-bottom:0.5rem;">Votre panier est vide</h2>
 <p style="color:var(--text-light);margin-bottom:2rem;">Découvrez nos bijoux spirituels et pierres naturelles</p>
 <a href="/produits" class="btn-primary">Découvrir la boutique</a>
 </div>`;
 if (summary) summary.style.display = 'none';
 return;
 }
 let totalAmount = 0;
 panier.forEach(p => totalAmount += parseFloat(p.price));
 const freeShipThreshold = 50;
 const progressPercent = Math.min(100, (totalAmount / freeShipThreshold) * 100);
 const remaining = Math.max(0, freeShipThreshold - totalAmount).toFixed(2);
 const progressHtml = `
 <div class="shipping-progress">
 <div class="shipping-progress-text">
 ${remaining > 0 
 ? `Plus que <strong style="color:var(--gold-dark);">${remaining}€</strong> pour la <strong>livraison offerte</strong> 🚚` 
 : `🎉 Vous bénéficiez de la <strong>livraison offerte</strong> !`}
 </div>
 <div class="shipping-progress-bar">
 <div class="shipping-progress-fill" style="width:${progressPercent}%"></div>
 </div>
 </div>
 `;
 const grouped = {};
 panier.forEach(p => {
 if (!grouped[p.handle]) grouped[p.handle] = { ...p, qty: 0 };
 grouped[p.handle].qty++;
 });
 let total = 0;
 items.innerHTML = progressHtml + Object.values(grouped).map(p => {
 const stotal = parseFloat(p.price) * p.qty;
 total += stotal;
 return `
 <div class="cart-item">
 ${p.img ? `<img src="${p.img}" alt="${p.title}">` : ''}
 <div style="flex:1;">
 <h4>${p.title}</h4>
 <div style="display:flex;align-items:center;gap:0.5rem;margin-top:0.5rem;">
 <button onclick="updateQty('${p.handle}', -1)" style="background:var(--beige);border:none;width:30px;height:30px;border-radius:8px;cursor:pointer;font-weight:700;font-size:1rem;transition:var(--transition);">−</button>
 <span style="font-weight:600;min-width:35px;text-align:center;">${p.qty}</span>
 <button onclick="updateQty('${p.handle}', 1)" style="background:var(--beige);border:none;width:30px;height:30px;border-radius:8px;cursor:pointer;font-weight:700;font-size:1rem;transition:var(--transition);">+</button>
 </div>
 </div>
 <div style="text-align:right;">
 <div style="font-size:1.1rem;font-weight:700;color:var(--gold-dark);">${stotal.toFixed(2)} €</div>
 <button onclick="retirerDuPanier('${p.handle}')" style="background:none;border:none;color:#c00;cursor:pointer;font-size:0.8rem;margin-top:0.3rem;transition:var(--transition);">🗑️ Supprimer</button>
 </div>
 </div>
 `;
 }).join('');
 document.getElementById('cart-total').textContent = `${total.toFixed(2)} €`;
 if (summary) summary.style.display = 'block';
 const btn = document.getElementById('checkout-btn');
 if (btn) {
 btn.onclick = async (e) => {
 e.preventDefault();
 await createShopifyCheckout();
 };
 }
});
window.addToCart = addToCart;
window.retirerDuPanier = retirerDuPanier;
window.updateQty = updateQty;
window.createShopifyCheckout = createShopifyCheckout;
window.showToast = showToast;